          }
      }
  }
  ```
- Test cache by creating a view:
  ```python
  from django.core.cache import cache

  def my_view(request):
      if 'my_key' in cache:
          value = cache.get('my_key')
      else:
          value = 'Computed Value'
          cache.set('my_key', value, timeout=30)
      return HttpResponse(value)
